    // =========================================================
    //  extensions.json  ―  「推奨する拡張機能」リスト
    // =========================================================
    // このファイルに書いた拡張機能は、ワークスペースを開いたとき
    // VS Code が「インストールしますか？」とおすすめしてくれる。
    // チームメンバー全員が同じ拡張機能を使えるようにするための仕組み。
    //
    // recommendations   = 「入れた方がいいよ」リスト
    // unwantedRecommendations = 「これは入れないで」リスト
    // ---------------------------------------------------------

    "recommendations": [
        // --- C/C++ 開発に必須 ---
        // Microsoft 公式。コード補完・デバッグ・定義ジャンプなど
        "ms-vscode.cpptools",

        // --- C# 開発に必須 ---
        // Microsoft 公式の C# 拡張。IntelliSense やデバッグ
        "ms-dotnettools.csharp",

        // --- Python（hook スクリプト用） ---
        "ms-python.python",

        // --- Git 関連 ---
        // Git の変更履歴を行ごとに表示（誰がいつ変えたか）
        "eamodio.gitlens",

        // --- エンコーディング ---
        // 文字コードの変換や確認に便利
        "bushick.vscode-encoding",

        // --- 見た目・効率化 ---
        // 対応するカッコを色分け表示（読みやすくなる）
        "coenraads.bracket-pair-colorizer-2",

        // インデントを可視化（レインボー表示）
        "oderwat.indent-rainbow",

        // 末尾の余計な空白を赤くハイライト
        "shardulm94.trailing-spaces",

        // --- ファイル形式 ---
        // XML ファイルの整形・ハイライト
        "dotjoshjohnson.xml",

        // Hex（16進数）エディタ。バイナリファイル閲覧用
        "ms-vscode.hexeditor"
    ],

    "unwantedRecommendations": []
}

