    // =========================================================
    //  tasks.json  ―  「タスク（ビルドなどの自動実行）」設定
    // =========================================================
    // VS Code の「ターミナル > タスクの実行」メニューや
    // ショートカットキー Ctrl+Shift+B で実行できるコマンドを定義する。
    //
    // たとえば「ビルド」ボタンを押したら MSBuild が走る、
    // というような設定をここに書く。
    //
    // version: タスク設定ファイルのバージョン（2.0.0 が現行）
    // tasks:   実行するタスクの配列（リスト）
    // ---------------------------------------------------------

    "version": "2.0.0",
    "tasks": [
        {
            // ---- タスク 1: ソリューション全体をビルド（Debug） ----
            "label": "Build all_cmp (Debug)",
            // → このタスクの名前。メニューに表示される

            "type": "shell",
            // → シェル（コマンドプロンプト）でコマンドを実行する

            "command": "msbuild",
            // → 実行するコマンド（MSBuild = Microsoft のビルドツール）

            "args": [
                "${workspaceFolder}/Build/Release/all_cmp/all_cmp.sln",
                // ↑ ビルド対象のソリューションファイル

                "/p:Configuration=Debug",
                // ↑ Debug モードでビルド（デバッグ情報付き）

                "/p:Platform=x64",
                // ↑ 64ビット向けにビルド

                "/m"
                // ↑ マルチプロセスビルド（並列処理で速くなる）
            ],

            "group": {
                "kind": "build",
                "isDefault": true
                // ↑ Ctrl+Shift+B で実行されるデフォルトのビルドタスク
            },

            "problemMatcher": "$msCompile",
            // ↑ ビルドエラーの出力を VS Code が解析して
            //   「問題」パネルに表示してくれる形式

            "presentation": {
                "reveal": "always",
                // ↑ タスク実行時にターミナルを自動で表示
                "panel": "shared"
                // ↑ 他のタスクとターミナルを共有
            }
        },
        {
            // ---- タスク 2: ソリューション全体をビルド（Release） ----
            "label": "Build all_cmp (Release)",
            "type": "shell",
            "command": "msbuild",
            "args": [
                "${workspaceFolder}/Build/Release/all_cmp/all_cmp.sln",
                "/p:Configuration=Release",
                "/p:Platform=x64",
                "/m"
            ],
            "group": "build",
            "problemMatcher": "$msCompile"
        },
        {
            // ---- タスク 3: netsrc（ネットワーク系）をビルド ----
            "label": "Build all_netsrc (Debug)",
            "type": "shell",
            "command": "msbuild",
            "args": [
                "${workspaceFolder}/Build/Release/all_netsrc/all_netsrc.sln",
                "/p:Configuration=Debug",
                "/p:Platform=x64",
                "/m"
            ],
            "group": "build",
            "problemMatcher": "$msCompile"
        },
        {
            // ---- タスク 4: ソリューションのクリーン（中間ファイル削除） ----
            "label": "Clean all_cmp",
            "type": "shell",
            "command": "msbuild",
            "args": [
                "${workspaceFolder}/Build/Release/all_cmp/all_cmp.sln",
                "/t:Clean",
                // ↑ /t:Clean = ビルドではなく「掃除」を実行
                "/p:Configuration=Debug",
                "/p:Platform=x64"
            ],
            "group": "build",
            "problemMatcher": "$msCompile"
        }
    ]
}

{
    // =========================================================
    //  launch.json  ―  「デバッグ実行」の設定
    // =========================================================
    // F5 キーを押したときに「どのプログラムを」「どうやって」
    // デバッグ実行するかを定義するファイル。
    //
    // ブレークポイント（止めたい行に赤い丸をつける）を設定して
    // F5 で実行すると、その行で止まって変数の中身を見られる。
    //
    // version: 設定ファイルのバージョン
    // configurations: デバッグ設定の配列（複数定義できる）
    // ---------------------------------------------------------

    "version": "0.2.0",
    "configurations": [
        {
            // ---- 設定 1: C/C++ プログラムをデバッグ ----
            "name": "(Windows) C/C++ Launch",
            // → デバッグ実行メニューに表示される名前

            "type": "cppvsdbg",
            // → デバッガの種類。cppvsdbg = Visual Studio のデバッガ

            "request": "launch",
            // → launch = プログラムを新しく起動してデバッグ
            //   attach = 既に動いているプログラムにつなぐ

            "program": "${workspaceFolder}/path/to/your.exe",
            // → デバッグしたい .exe ファイルのパス
            //   ★ 実際のパスに書き換えて使う ★

            "args": [],
            // → プログラムに渡す引数（コマンドライン引数）

            "stopAtEntry": false,
            // → true にすると main() の最初の行で自動停止

            "cwd": "${workspaceFolder}",
            // → プログラムの作業ディレクトリ（カレントディレクトリ）

            "environment": [],
            // → 環境変数の追加設定（必要なら書く）

            "console": "integratedTerminal"
            // → 出力先。VS Code 内蔵ターミナルに表示
        },
        {
            // ---- 設定 2: 動作中のプロセスにアタッチ ----
            "name": "(Windows) C/C++ Attach",
            "type": "cppvsdbg",

            "request": "attach",
            // → attach = 既に動いているプロセスに接続する
            //   プロセス一覧が表示されるので、選んでアタッチ

            "processId": "${command:pickProcess}"
            // → 実行中のプロセスを選択するダイアログが出る
        },
        {
            // ---- 設定 3: C#（.NET）プログラムをデバッグ ----
            "name": "(Windows) C# Launch",
            "type": "coreclr",
            // → coreclr = .NET のデバッガ

            "request": "launch",
            "program": "${workspaceFolder}/path/to/your.dll",
            // → デバッグしたい .dll または .exe のパス
            //   ★ 実際のパスに書き換えて使う ★

            "args": [],
            "cwd": "${workspaceFolder}",
            "stopAtEntry": false,
            "console": "integratedTerminal"
        }
    ]
}

